var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"방금 그건…… 저격?","JPN":"今のは……狙撃？","ENG":"What...?! A sniper?!","TWN":"剛剛那是……狙擊？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"언니 방금 나한테 빚 하나 진 거다? 내가 안 잡아 당겼으면 총이 아니라 언니 팔이 날아갔을걸?","JPN":"ユリさん、今の貸しですよ？　私が引っ張らなかったら銃じゃなくてユリさんの腕が吹っ飛んでたんだから。","ENG":"You owe me one, Yuri. If I hadn't pulled you over, you would have lost an arm.","TWN":"悠麗姊姊，你欠我一命！剛才要不是我把你拉開，飛出去的就會是你的手臂，而不是槍咧！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"근데 장전은 제대로 했던 거 맞아?","JPN":"ていうか、ちゃんと装填はしてたんですか？","ENG":"Hey, did you even reload the gun correctly?","TWN":"你確定有裝好子彈嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"지금 그게 중요한 게 아냐!","JPN":"今はそれどころじゃない！","ENG":"That’s not important right now!","TWN":"現在重點不是那個！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대장, 방금 어디서 쏜 거야?","JPN":"隊長、今のどこからだ？","ENG":"Captain, did you see where that bullet came from?","TWN":"隊長，剛才是從哪裡開槍的？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L8_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"지금 찾고 있다! 일단 타깃 확보해서 엄폐부터 해!","JPN":"今探してる！　とりあえずターゲットを確保して隠れろ！","ENG":"I'm scanning the area! But first, secure the target and find some cover!","TWN":"正在找！先看好目標，找好掩護！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L13_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"칫……! 어떤 녀석들이야?!","JPN":"ちっ……！　やつら何者だよ！？","ENG":"Tch...! Who the heck are they?!","TWN":"嘖……！到底是誰？！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GRAY_NPC_MANSION_NULL","text":{"KOREA":"실례했습니다. 하지만 손님을 모시라는 마스터의 지시이기에.","JPN":"失礼いたしました。ですが、お客様をお迎えしろ、とのマスターからのご指示ですので。","ENG":"Pardon us. But we have orders from Master to bring our guest safe and unharmed.","TWN":"不好意思，我們是奉主人之命來招呼客人的。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"메이드? 게다가 한두 명이 아니잖아?","JPN":"メイド？　しかも一人じゃない？","ENG":"Maids? And there are lots of them!","TWN":"女僕？而且還不只一、二個？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"같은 편이 더 있었나 보네. 쉽게 마무리하긴 그른 것 같아, 유리 언니.","JPN":"味方がもっといたんだね。簡単に終わらせるのは無理みたいですよ、ユリさん。","ENG":"Looks like she had some backup with her. Guess we won't be finishing this job that easily.","TWN":"似乎還有同夥，看來沒那麼好收尾喔，悠麗姊姊。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"일단 피하지 않을래? 저 사람들 우리처럼 말로 풀기 싫어하는 타입 같은데.","JPN":"とりあえず避けますか？　あの人たち、私たちみたいに話し合いで解決するのが嫌いなタイプみたいですが。","ENG":"How about we get out of here first? I don't think they're the type to use words to settle this.","TWN":"還是先逃吧？那些人好像和我們一樣，是動手不動口的類型欸？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"당신들은…… 마스터의……?","JPN":"あなたたちは……マスターの……？","ENG":"You're... from Mansion...?","TWN":"你們是……主人的……？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"GRAY_NPC_MANSION_NULL","text":{"KOREA":"치명상을 입은 상태군요. 서둘러 옮기도록 하세요.","JPN":"致命傷を負っていますね。急いで運びなさい。","ENG":"You are injured. Take her back quickly.","TWN":"你傷得很嚴重，趕緊離開這裡吧。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"제 몸에…… 손대지 마세요…….","JPN":"私の体に……手を出さないでください……","ENG":"Don't... touch me...!","TWN":"請不要……碰我……"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"GRAY_NPC_MANSION_NULL","text":{"KOREA":"마스터께 말씀하십시오. 저희는 지시를 수행할 뿐입니다.","JPN":"マスターに直接おっしゃってください。私たちはご指示に従うまでです。","ENG":"Please tell that to Master. We are only following orders.","TWN":"跟主人說吧，我們只是奉命行事而已。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대장, 저것들은 어떻게 된 거야?","JPN":"隊長、あれは何なんだ？","ENG":"Captain, what are they doing?","TWN":"隊長，那些人是怎麼回事？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"아무래도 조직이 사라졌다는 건 잘못된 정보였나 보군.","JPN":"どうやら組織が消えたというのは間違った情報だったようだな。","ENG":"I guess the intel about the organization collapsing was wrong.","TWN":"看來組織瓦解的消息是錯誤的。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"일단은 물러서자. 숫자로도 우리가 밀려.","JPN":"いったん撤退しよう。数的にも俺たちが不利だ。","ENG":"Let's retreat for now. We're too outnumbered to fight.","TWN":"總之先撤吧，要比人數我們也比不過人家。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"아니. 나는 확인해 봐야겠어.","JPN":"いや。私は確認したい。","ENG":"No. I need to find out what's going on for myself.","TWN":"不，我要確認清楚。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"저 타깃이 정말 맨션이란 놈들과 인연을 끊었는지…….","JPN":"あのターゲットが本当にマンションのやつらと縁を切ったのか……","ENG":"If our target had really cut ties with Mansion...","TWN":"目標是真的已經和曼森的人斷乾淨……"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"아이들을 들먹인 건 살기 위한 가식이었는지.","JPN":"子どもたちの話を云々したのは生きるための方便だったのか。","ENG":"Or if she was pretending to care for the others to save herself.","TWN":"還是她剛才求我放過其他人，只是想活命的假好心？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"타깃에게 직접 물어봐야겠어.","JPN":"ターゲットに直接聞く。","ENG":"I'll have to ask the target directly.","TWN":"我要直接問清楚。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"잠깐! 멈춰, 이유리!","JPN":"待て！　やめろ、カスカベ！","ENG":"Yuri! Stop!","TWN":"等等！你站住，李悠麗！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"젠장! 저 녀석 성질머리는 어째 나아지는 기미가 없어!","JPN":"くそ！　あいつの気性はどうしてあのままなんだ！","ENG":"Dammit! When will she learn to control her temper?!","TWN":"該死！那傢伙的脾氣不能改改嗎！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"그럼 그냥 언니 빼고 우리끼리 튈까요, 민우 대장?","JPN":"じゃあ、ユリさんなしで逃げます？　マツダ隊長。","ENG":"Then should we leave her and get out of here just you and me, Captain?","TWN":"那我們要扔下悠麗姊姊自己逃嗎，民宇隊長？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L47_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"농담 집어치우고 얼른 움직이나 해! 유리를 엄호한다!","JPN":"冗談言ってないでさっさと動け！　カスカベを援護する！","ENG":"Stop joking around and get moving! We need to cover Yuri!","TWN":"別再開玩笑，趕緊行動！掩護悠麗！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};